/// <summary>
/// Represents the freight forwarder table for the ETGSPAIN model.
/// </summary>
public class ETGSPAINPurchFreightForwarderTable extends common
{
}

Method.Source:
/// <summary>
/// Finds a record in the ETGSPAINPurchFreightForwarderTable.
/// </summary>
/// <param name="_freightForwarder">The freight forwarder number.</param>
/// <param name="_forUpdate">Specifies if the record should be locked for update.</param>
/// <returns>Returns the found ETGSPAINPurchFreightForwarderTable record.</returns>
static ETGSPAINPurchFreightForwarderTable find(  ETGSPAINFreightForwarder    _freightForwarder,
                                        boolean                 _forUpdate = false)
{
    ETGSPAINPurchFreightForwarderTable freightForwarderTable;

    if (_freightForwarder)
    {
        if (_forUpdate)
        {
            freightForwarderTable.selectForUpdate(_forUpdate);
        }

        select firstonly freightForwarderTable
            index hint FreightForwarderIdx
            where freightForwarderTable.FreightForwarder == _freightForwarder;
    }

    return freightForwarderTable;
}

/// <summary>
/// Checks if a record exists in the ETGSPAINPurchFreightForwarderTable.
/// </summary>
/// <param name="_freightForwarder">The freight forwarder number.</param>
/// <returns>Returns true if the record exists, otherwise false.</returns>
static boolean exist(ETGSPAINFreightForwarder  _freightForwarder)
{
    return _freightForwarder && (select firstonly RecId from ETGSPAINPurchFreightForwarderTable
                                index hint FreightForwarderIdx
                                where ETGSPAINPurchFreightForwarderTable.FreightForwarder == _freightForwarder).RecId != 0;
}
